create table users (id int primary key, prenom varchar(256), nom varchar(256), nom_complet varchar(256), nom_utilisateur varchar(256), titre int(12), role int(12), localisation varchar(50), email varchar(256), numero_telephone_1 varchar(28), numero_telephone_2 varchar(28), lieu_naissance varchar(50), ville varchar(50), province_etat varchar(50), pays varchar(50), boite_postale varchar(50), date_naissance date, mot_passe mediumblob, image_dun_utilisateur mediumblob);
